    fputc((mdat_payload_start >> 8) & 0xff, f);
    fputc(mdat_payload_start & 0xff, f);
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x0e, f);
    fputc((mdat_payload_start + 14) >> 24, f);
    fputc((mdat_payload_start + 14) >> 16, f);
    fputc((mdat_payload_start + 14) >> 8, f);
    fputc(mdat_payload_start + 14, f);
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x0e, f);
    fseek(f, mdat_end, SEEK_SET);

    /* iprp box: ipco(8+16+23+58=105) + ipma(23) = 128 */
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x80, f);
    fputc('i', f); fputc('p', f); fputc('r', f); fputc('p', f);
    /* ipco box: size=105 */
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x69, f);
    fputc('i', f); fputc('p', f); fputc('c', f); fputc('o', f);
    /* ispe box: size=16 */
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x10, f);
    fputc('i', f); fputc('s', f); fputc('p', f); fputc('e', f);
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x00, f); fputc(0x00, f); fputc(0x01, f); fputc(0x00, f);
    fputc(0x00, f); fputc(0x00, f); fputc(0x01, f); fputc(0x00, f);
    /* av1C box: size=23 */
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x17, f);
    fputc('a', f); fputc('v', f); fputc('1', f); fputc('C', f);
    fputc(0x81, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x0c, f); fputc(0x08, f); fputc(0x88, f); fputc(0x07, f);
    fputc(0x07, f); fputc(0xff, f); fputc(0x01, f); fputc(0xff, f);
    fputc(0x01, f);
    /* auxC box: size=58 */
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x3a, f);
    fputc('a', f); fputc('u', f); fputc('x', f); fputc('C', f);
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputs("urn:mpeg:mpegB:cicp:systems:auxiliary:alpha", f);
    fputc(0x00, f);
    /* ipma box: size=23 */
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x17, f);
    fputc('i', f); fputc('p', f); fputc('m', f); fputc('a', f);
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x02, f); /* entry_count=2 */
    fputc(0x00, f); fputc(0x01, f); fputc(0x02, f); fputc(0x01, f); fputc(0x02, f);
    fputc(0x00, f); fputc(0x02, f); fputc(0x02, f); fputc(0x01, f); fputc(0x03, f);

    fclose(f);
    return 0;
}
